// ── Harmonia Lead Pipeline: classify + filter ──
const items = $input.all();
const rawItems = [];
const cleanItems = [];

for (const item of items) {
  const row = item.json;

  // Branch 0: ALL raw rows pass through untouched
  rawItems.push({ json: { ...row } });

  // ── Qualification gate ──
  const companyName = (row['Company Name'] || '').trim();
  const corpPhone   = (row['Corporate Phone'] || '').trim();
  const mobilePhone = (row['Mobile Phone'] || '').trim();
  const homePhone   = (row['Home Phone'] || '').trim();

  if (!companyName) continue;                   // no company = skip
  if (!corpPhone && !mobilePhone && !homePhone) continue; // no phone = skip

  // ── ICP classification ──
  const kw    = (row['Keywords'] || '').toLowerCase();
  const title = (row['Title'] || '').toLowerCase();
  const co    = companyName.toLowerCase();

  let icp = 'other';

  if (kw.includes('barber') || kw.includes('haircuts for men') || co.includes('barber')) {
    icp = 'barbershop';
  } else if (
    kw.includes('salon') || kw.includes('hair care') ||
    kw.includes('hairstyl') || kw.includes('cosmetolog') ||
    title.includes('salon') || title.includes('stylist') ||
    co.includes('salon')
  ) {
    icp = 'salon';
  } else if (
    kw.includes('nail salon') || kw.includes('manicur') ||
    kw.includes('pedicur') || co.includes('nail')
  ) {
    icp = 'nail_salon';
  } else if (
    kw.includes('waxing') || kw.includes('sugaring') ||
    kw.includes('esthetician') || kw.includes('lash') ||
    kw.includes('medspa') || kw.includes('medical spa') ||
    kw.includes('facial') || co.includes('spa') ||
    co.includes('wax') || co.includes('lash')
  ) {
    icp = 'beauty_spa';
  }

  if (icp === 'other') continue;                // not our vertical = skip

  // ── Zip extraction from Company Address ──
  const addr = row['Company Address'] || '';
  const zipMatch = addr.match(/\b(\d{5}(?:-\d{4})?)\b/);

  // ── Unique lead ID ──
  const ts   = Date.now();
  const rand = Math.random().toString(36).substring(2, 6);

  cleanItems.push({
    json: {
      id:           `HL-${ts}-${rand}`,
      biz:          companyName,
      owner:        `${(row['First Name'] || '').trim()} ${(row['Last Name'] || '').trim()}`.trim(),
      owner_title:  (row['Title'] || '').trim(),
      corporate_phone: corpPhone,
      mobile_phone:    mobilePhone,
      home_phone:      homePhone,
      address:      (row['Company Address'] || '').trim(),
      city:         (row['City'] || '').trim(),
      state:        (row['State'] || '').trim(),
      zip:          zipMatch ? zipMatch[1] : '',
      website:      (row['Website'] || '').trim(),
      icp:          icp,
      phone_source: 'apollo',
      status:       'new',
      created_at:   new Date().toISOString(),
      email:        (row['Email'] || '').trim(),
      linkedin:     (row['Person Linkedin Url'] || '').trim()
    }
  });
}

return [rawItems, cleanItems];
